def solve(age, heart_rate_bpm, systolic_bp_mmHg, serum_creatinine_mg_dl, killip_class, cardiac_arrest, st_segment_shift, myocardial_marker_elevation):
    # Step 1: Calculate the age score based on the patient's age range for the GRACE 2.0 risk assessment
    if age <= 30:
        age_score = 0
    elif 30 <= age <= 39:
        age_score = 8
    elif 40 <= age <= 49:
        age_score = 25
    elif 50 <= age <= 59:
        age_score = 41
    elif 60 <= age <= 69:
        age_score = 58
    elif 70 <= age <= 79:
        age_score = 75
    elif 80 <= age <= 89:
        age_score = 91
    elif age >= 90:
        age_score = 100
    else:
        age_score = 0  # Default value for age outside specified ranges

    yield {
        "step_name": "age_score_calculation",
        "step_description": "Calculate the age score based on the patient's age range for the GRACE 2.0 risk assessment.",
        "step_result": age_score,
        "unit": None
    }

    # Step 2: Calculate the heart rate score based on the patient's heart rate range for the GRACE 2.0 risk assessment
    if heart_rate_bpm <= 49:
        heart_rate_score = 0
    elif 50 <= heart_rate_bpm <= 69:
        heart_rate_score = 3
    elif 70 <= heart_rate_bpm <= 89:
        heart_rate_score = 9
    elif 90 <= heart_rate_bpm <= 109:
        heart_rate_score = 15
    elif 110 <= heart_rate_bpm <= 149:
        heart_rate_score = 24
    elif 150 <= heart_rate_bpm <= 199:
        heart_rate_score = 38
    elif heart_rate_bpm >= 200:
        heart_rate_score = 46
    else:
        heart_rate_score = 0  # Default value for heart rate outside specified ranges

    yield {
        "step_name": "heart_rate_score_calculation",
        "step_description": "Calculate the heart rate score based on the patient's heart rate range for the GRACE 2.0 risk assessment.",
        "step_result": heart_rate_score,
        "unit": None
    }

    # Step 3: Calculate the systolic blood pressure score based on the patient's systolic blood pressure range for the GRACE 2.0 risk assessment
    if systolic_bp_mmHg <= 79:
        systolic_bp_score = 58
    elif 80 <= systolic_bp_mmHg <= 99:
        systolic_bp_score = 53
    elif 100 <= systolic_bp_mmHg <= 119:
        systolic_bp_score = 43
    elif 120 <= systolic_bp_mmHg <= 139:
        systolic_bp_score = 34
    elif 140 <= systolic_bp_mmHg <= 159:
        systolic_bp_score = 24
    elif 160 <= systolic_bp_mmHg <= 199:
        systolic_bp_score = 10
    elif systolic_bp_mmHg >= 200:
        systolic_bp_score = 0
    else:
        systolic_bp_score = 0  # Default value for systolic BP outside specified ranges

    yield {
        "step_name": "systolic_bp_score_calculation",
        "step_description": "Calculate the systolic blood pressure score based on the patient's systolic blood pressure range for the GRACE 2.0 risk assessment.",
        "step_result": systolic_bp_score,
        "unit": None
    }

    # Step 4: Calculate the creatinine score based on the patient's serum creatinine level for the GRACE 2.0 risk assessment
    if 0 <= serum_creatinine_mg_dl <= 0.39:
        creatinine_score = 1
    elif 0.40 <= serum_creatinine_mg_dl <= 0.79:
        creatinine_score = 4
    elif 0.80 <= serum_creatinine_mg_dl <= 1.19:
        creatinine_score = 7
    elif 1.20 <= serum_creatinine_mg_dl <= 1.59:
        creatinine_score = 10
    elif 1.60 <= serum_creatinine_mg_dl <= 1.99:
        creatinine_score = 13
    elif 2.00 <= serum_creatinine_mg_dl <= 3.99:
        creatinine_score = 21
    elif serum_creatinine_mg_dl >= 4.0:
        creatinine_score = 28
    else:
        creatinine_score = 0  # Default value for creatinine level outside specified ranges

    yield {
        "step_name": "creatinine_score_calculation",
        "step_description": "Calculate the creatinine score based on the patient's serum creatinine level for the GRACE 2.0 risk assessment.",
        "step_result": creatinine_score,
        "unit": None
    }

    # Step 5: Calculate the Killip class score based on the patient's clinical classification for the GRACE 2.0 risk assessment
    if killip_class == "I":
        killip_score = 0
    elif killip_class == "II":
        killip_score = 20
    elif killip_class == "III":
        killip_score = 39
    elif killip_class == "IV":
        killip_score = 59
    else:
        killip_score = 0  # Default value for invalid Killip class input

    yield {
        "step_name": "killip_class_score_calculation",
        "step_description": "Calculate the Killip class score based on the patient's clinical classification for the GRACE 2.0 risk assessment.",
        "step_result": killip_score,
        "unit": None
    }

    # Step 6: Calculate the cardiac arrest score based on whether the patient had cardiac arrest upon admission for the GRACE 2.0 risk assessment
    if cardiac_arrest == "no":
        cardiac_arrest_score = 0
    elif cardiac_arrest == "yes":
        cardiac_arrest_score = 39
    else:
        cardiac_arrest_score = 0  # Default value for invalid cardiac arrest input

    yield {
        "step_name": "cardiac_arrest_score_calculation",
        "step_description": "Calculate the cardiac arrest score based on whether the patient had cardiac arrest upon admission for the GRACE 2.0 risk assessment.",
        "step_result": cardiac_arrest_score,
        "unit": None
    }

    # Step 7: Calculate the ST segment shift score based on whether the patient has ST segment shifts >0.5 mm for the GRACE 2.0 risk assessment
    if st_segment_shift == "no":
        st_segment_shift_score = 0
    elif st_segment_shift == "yes":
        st_segment_shift_score = 28
    else:
        st_segment_shift_score = 0  # Default value for invalid ST segment shift input

    yield {
        "step_name": "st_segment_shift_score_calculation",
        "step_description": "Calculate the ST segment shift score based on whether the patient has ST segment shifts >0.5 mm for the GRACE 2.0 risk assessment.",
        "step_result": st_segment_shift_score,
        "unit": None
    }

    # Step 8: Calculate the myocardial marker elevation score based on whether the patient has elevated myocardial markers for the GRACE 2.0 risk assessment
    if myocardial_marker_elevation == "no":
        myocardial_marker_score = 0
    elif myocardial_marker_elevation == "yes":
        myocardial_marker_score = 14
    else:
        myocardial_marker_score = 0  # Default value for invalid myocardial marker input

    yield {
        "step_name": "myocardial_marker_elevation_score_calculation",
        "step_description": "Calculate the myocardial marker elevation score based on whether the patient has elevated myocardial markers for the GRACE 2.0 risk assessment.",
        "step_result": myocardial_marker_score,
        "unit": None
    }

    # Step 9: Calculate the total GRACE 2.0 score by summing all individual scores for the risk assessment
    total_grace_score = (age_score + heart_rate_score + systolic_bp_score + creatinine_score + 
                         killip_score + cardiac_arrest_score + st_segment_shift_score + myocardial_marker_score)

    yield {
        "step_name": "total_grace_2_0_score_calculation",
        "step_description": "Calculate the total GRACE 2.0 score by summing all individual scores for the risk assessment.",
        "step_result": total_grace_score,
        "unit": None
    }

    return total_grace_score
